     1→import Stripe from 'stripe';
     2→
     3→// Lazy initialization to avoid build-time env var errors
     4→let _stripe: Stripe | null = null;
     5→export const getStripe = () => {
     6→  if (!_stripe) {
     7→    _stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
     8→      apiVersion: '2024-04-10',
     9→      typescript: true,
    10→    });
    11→  }
    12→  return _stripe;
    13→};
    14→
    15→// Keep backward-compatible export (getter pattern)
    16→export const stripe = new Proxy({} as Stripe, {
    17→  get(_, prop) {
    18→    return (getStripe() as any)[prop];
    19→  },
    20→});
    21→
    22→export const PLANS = {
    23→  starter: process.env.STRIPE_PRICE_STARTER || 'price_starter_monthly', // TODO: Set STRIPE_PRICE_STARTER in env
    24→  pro: process.env.STRIPE_PRICE_PRO || 'price_pro_monthly',             // TODO: Set STRIPE_PRICE_PRO in env
    25→  agency: process.env.STRIPE_PRICE_AGENCY || 'price_agency_monthly',   // TODO: Set STRIPE_PRICE_AGENCY in env
    26→};
    27→
    28→export function getPlanFromPriceId(priceId: string): 'starter' | 'pro' | 'agency' {
    29→  if (priceId === PLANS.agency) return 'agency';
    30→  if (priceId === PLANS.pro) return 'pro';
    31→  return 'starter';
    32→}

